1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote", () => {
6	    it("returns empty results for empty steps", () => {
7	      const result = runScenario({ customer: { yearsWithMHPCO: 0 }, steps: [] });
8	      expect(result).toEqual({ results: [] });
9	    });
10	    it("quotes a single sword for a new customer (base + first insurance + processing fee)", () => {
11	      const result = runScenario({
12	        customer: { yearsWithMHPCO: 0 },
13	        steps: [
14	          { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
15	        ],
16	      });
17	      expect(result).toEqual({ results: [{ premium: 115 }] });
18	    });
19	    it("quotes other main item types (amulet, staff, potion)", () => {
20	      const customer = { yearsWithMHPCO: 0 };
21	      const amulet = runScenario({
22	        customer,
23	        steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }] }],
24	      });
25	      expect(amulet).toEqual({ results: [{ premium: 71 }] });
26	      const staff = runScenario({
27	        customer,
28	        steps: [{ op: "quote", items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }] }],
29	      });
30	      expect(staff).toEqual({ results: [{ premium: 93 }] });
31	      const potion = runScenario({
32	        customer,
33	        steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
34	      });
35	      expect(potion).toEqual({ results: [{ premium: 49 }] });
36	    });
37	    it("sums multiple main items in one quote", () => {
38	      const result = runScenario({
39	        customer: { yearsWithMHPCO: 0 },
40	        steps: [
41	          {
42	            op: "quote",
43	            items: [
44	              { type: "sword", material: "steel", enchantment: 0, cursed: false },
45	              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
46	            ],
47	          },
48	        ],
49	      });
50	      expect(result).toEqual({ results: [{ premium: 181 }] });
51	    });
52	    it("quotes a single component (rune) at component pricing", () => {
53	      const result = runScenario({
54	        customer: { yearsWithMHPCO: 0 },
55	        steps: [
56	          { op: "quote", items: [{ type: "rune", material: "stone", enchantment: 0, cursed: false }] },
57	        ],
58	      });
59	      expect(result).toEqual({ results: [{ premium: 33 }] });
60	    });
61	    it("bundles 3 alike components at the special base premium of 60 G", () => {
62	      const result = runScenario({
63	        customer: { yearsWithMHPCO: 0 },
64	        steps: [
65	          {
66	            op: "quote",
67	            items: [
68	              { type: "rune", material: "stone", enchantment: 0, cursed: false },
69	              { type: "rune", material: "stone", enchantment: 0, cursed: false },
70	              { type: "rune", material: "stone", enchantment: 0, cursed: false },
71	            ],
72	          },
73	        ],
74	      });
75	      expect(result).toEqual({ results: [{ premium: 71 }] });
76	    });
77	    it("does not bundle 3 components of different kinds", () => {
78	      const result = runScenario({
79	        customer: { yearsWithMHPCO: 0 },
80	        steps: [
81	          {
82	            op: "quote",
83	            items: [
84	              { type: "rune", material: "stone", enchantment: 0, cursed: false },
85	              { type: "rune", material: "stone", enchantment: 0, cursed: false },
86	              { type: "moonstone", material: "stone", enchantment: 0, cursed: false },
87	            ],
88	          },
89	        ],
90	      });
91	      // 2 runes (50) + 1 moonstone (25) = 75 base; *1.1 = 82.5 → ceil 83; +5 = 88
92	      expect(result).toEqual({ results: [{ premium: 88 }] });
93	    });
94	    it("applies 50% cursed surcharge per item", () => {
95	      const result = runScenario({
96	        customer: { yearsWithMHPCO: 0 },
97	        steps: [
98	          { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }] },
99	        ],
100	      });
101	      // base 100 *1.5 cursed = 150 *1.1 first insurance = 165 +5 = 170
102	      expect(result).toEqual({ results: [{ premium: 170 }] });
103	    });
104	    it("applies 30% enchantment surcharge for enchantment >= 5", () => {
105	      const result = runScenario({
106	        customer: { yearsWithMHPCO: 0 },
107	        steps: [
108	          { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }] },
109	        ],
110	      });
111	      // base 100 *1.3 = 130 *1.1 first ins = 143 +5 = 148
112	      expect(result).toEqual({ results: [{ premium: 148 }] });
113	    });
114	    it("applies 20% loyalty discount for customers with >= 2 years", () => {
115	      const result = runScenario({
116	        customer: { yearsWithMHPCO: 2 },
117	        steps: [
118	          { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
119	        ],
120	      });
121	      // base 100 *0.8 loyalty = 80 *1.1 first ins = 88 +5 = 93
122	      expect(result).toEqual({ results: [{ premium: 93 }] });
123	    });
124	    it("applies 15% subsequent-contract discount to quotes after the first", () => {
125	      const result = runScenario({
126	        customer: { yearsWithMHPCO: 0 },
127	        steps: [
128	          { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
129	          { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
130	        ],
131	      });
132	      // 1st: 100*1.1 +5 = 115
133	      // 2nd (subsequent, no first-ins): 100*0.85 +5 = 90
134	      expect(result).toEqual({ results: [{ premium: 115 }, { premium: 90 }] });
135	    });
136	    it.todo("rounds the final premium up to whole G (in MHPCO favor)");
137	  });
138	
139	  describe("Claim", () => {
140	    it.todo("applies 100 G deductible to a basic claim");
141	    it.todo("reimburses 50% for items with enchantment >= 8 (after deductible)");
142	    it.todo("fully reimburses items made of dragon material (after deductible)");
143	    it.todo("returns 0 payout when deductible exceeds reimbursable amount");
144	  });
145	});
