1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] } | { op: "claim" };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const FIRST_INSURANCE_MULTIPLIER = 1.1;
15	const PROCESSING_FEE = 5;
16	
17	const ceilToWholeG = (amount: number): number =>
18	  Math.ceil(Math.round(amount * 100) / 100);
19	
20	const COMPONENT_BUNDLE_PRICE = 60;
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const CURSED_SURCHARGE = 1.5;
24	const ENCHANTMENT_SURCHARGE = 1.3;
25	const ENCHANTMENT_THRESHOLD = 5;
26	
27	const itemMultiplier = (item: Item): number =>
28	  (item.cursed ? CURSED_SURCHARGE : 1) *
29	  ((item.enchantment ?? 0) >= ENCHANTMENT_THRESHOLD ? ENCHANTMENT_SURCHARGE : 1);
30	
31	const sumItemsAtUnitPrice = (items: Item[], unitPrice: number): number =>
32	  items.reduce((sum, item) => sum + unitPrice * itemMultiplier(item), 0);
33	
34	const baseForGroup = (type: string, group: Item[]): number => {
35	  const unitPrice = BASE_PREMIUM[type] ?? 0;
36	  if (!COMPONENT_TYPES.has(type)) {
37	    return sumItemsAtUnitPrice(group, unitPrice);
38	  }
39	  const bundleCount = Math.floor(group.length / 3);
40	  const singles = group.slice(bundleCount * 3);
41	  return bundleCount * COMPONENT_BUNDLE_PRICE + sumItemsAtUnitPrice(singles, unitPrice);
42	};
43	
44	const groupByType = (items: Item[]): Map<string, Item[]> => {
45	  const groups = new Map<string, Item[]>();
46	  for (const item of items) {
47	    const list = groups.get(item.type) ?? [];
48	    list.push(item);
49	    groups.set(item.type, list);
50	  }
51	  return groups;
52	};
53	
54	const LOYALTY_DISCOUNT = 0.8;
55	const LOYALTY_YEARS_THRESHOLD = 2;
56	
57	const customerMultiplier = (customer: Scenario["customer"]): number =>
58	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 1;
59	
60	const baseForItems = (items: Item[]): number =>
61	  [...groupByType(items)].reduce(
62	    (sum, [type, group]) => sum + baseForGroup(type, group),
63	    0,
64	  );
65	
66	const SUBSEQUENT_CONTRACT_DISCOUNT = 0.85;
67	
68	const contractMultiplier = (quoteIndex: number): number =>
69	  quoteIndex === 0 ? FIRST_INSURANCE_MULTIPLIER : SUBSEQUENT_CONTRACT_DISCOUNT;
70	
71	const quote = (items: Item[], customer: Scenario["customer"], quoteIndex: number): number => {
72	  const adjusted = baseForItems(items) * customerMultiplier(customer) * contractMultiplier(quoteIndex);
73	  return ceilToWholeG(adjusted) + PROCESSING_FEE;
74	};
75	
76	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
77	  let quoteIndex = 0;
78	  const results = scenario.steps.map((step) => {
79	    if (step.op === "quote") {
80	      const result = { premium: quote(step.items, scenario.customer, quoteIndex) };
81	      quoteIndex++;
82	      return result;
83	    }
84	    return {};
85	  });
86	  return { results };
87	};
