const runStep = (
  step: Step,
  customer: Scenario["customer"],
  quoteIndex: number,
): { result: unknown; nextQuoteIndex: number } => {
  if (step.op === "quote") {
    return {
      result: { premium: quote(step.items, customer, quoteIndex) },
      nextQuoteIndex: quoteIndex + 1,
    };
  }
  return { result: {}, nextQuoteIndex: quoteIndex };
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const { results } = scenario.steps.reduce<{ results: unknown[]; quoteIndex: number }>(
    (acc, step) => {
      const { result, nextQuoteIndex } = runStep(step, scenario.customer, acc.quoteIndex);
      return { results: [...acc.results, result], quoteIndex: nextQuoteIndex };
    },
    { results: [], quoteIndex: 0 },
  );
  return { results };
};

